import pika
import json
import time
from datetime import datetime

class TaskPublisher:
    def __init__(self):
        self.connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue='task_queue', durable=True)
    
    def publish_task(self, task_data):
        message = json.dumps(task_data)
        self.channel.basic_publish(
            exchange='',
            routing_key='task_queue',
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f" [x] Sent task: {message}")
    
    def close(self):
        self.connection.close()

class TaskConsumer:
    def __init__(self):
        self.connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue='task_queue', durable=True)
        self.channel.basic_qos(prefetch_count=1)
    
    def process_task(self, ch, method, properties, body):
        task_data = json.loads(body)
        print(f" [x] Received task: {task_data}")
        
        try:
            # Simulate task processing
            task_type = task_data.get('type', 'unknown')
            task_id = task_data.get('id', 'unknown')
            
            if task_type == 'email':
                time.sleep(2)
                print(f" [x] Processing email task {task_id}")
            elif task_type == 'report':
                time.sleep(3)
                print(f" [x] Processing report task {task_id}")
            else:
                time.sleep(1)
                print(f" [x] Processing generic task {task_id}")
            
            print(f" [x] Completed task: {task_id}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except Exception as e:
            print(f" [x] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    
    def start_consuming(self):
        self.channel.basic_consume(queue='task_queue', on_message_callback=self.process_task)
        print(' [*] Waiting for tasks. To exit press CTRL+C')
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print(' [*] Interrupted')
            self.channel.stop_consuming()
            self.connection.close()

